  ocp_rhel_license_month_inr:7000,    // RHEL container OS license/month
  // ── Nutanix AHV ──
  nut_cpu_per_core_month_inr:480,     // Nutanix vCPU/core/month
  nut_ram_per_gb_month_inr:190,       // Nutanix RAM/GB/month
  nut_ssd_per_gb_month_inr:14,        // Nutanix SSD/GB/month
  nut_hdd_per_gb_month_inr:7,         // Nutanix HDD/GB/month
  nut_windows_license_month_inr:12500,
  nut_rhel_license_month_inr:10000,
