function ContactUs({ p }) {
  const [open, setOpen] = useState(false);
  const [copiedEmail, setCopiedEmail] = useState(null);
  const ref = useRef(null);

  useEffect(() => {
    function handleClick(e) {
      if (ref.current && !ref.current.contains(e.target)) setOpen(false);
    }
    if (open) document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, [open]);

  function copyEmail(email) {
    navigator.clipboard.writeText(email).then(() => {
      setCopiedEmail(email);
      setTimeout(() => setCopiedEmail(null), 2000);
    });
  }

  return (
    <div ref={ref} style={{ position: "relative" }}>
      <button
        className="btn btn-sm"
        onClick={() => setOpen(o => !o)}
        style={{
          background: open ? `${p.cyan}20` : p.panelAlt,
          border: `1px solid ${open ? p.cyan : p.border}`,
          color: open ? p.cyan : p.textSub,
          fontWeight: 600, gap: 5,
          transition: "all .2s",
        }}
      >
        📞 Support
      </button>

      {open && (
        <div style={{
          position: "absolute", right: 0, top: "calc(100% + 8px)",
          width: 500, background: p.panel, border: `1px solid ${p.border}`,
          borderRadius: 14, boxShadow: "0 20px 60px rgba(0,0,0,.6)",
          zIndex: 600, animation: "fadeUp .15s ease", overflow: "hidden",
          maxHeight: "85vh", display: "flex", flexDirection: "column",
        }}>
          {/* Header */}
          <div style={{
            padding: "12px 16px", borderBottom: `1px solid ${p.border}`,
            background: `linear-gradient(135deg,${p.accent}18,${p.cyan}10)`,
            display: "flex", alignItems: "center", gap: 10, flexShrink: 0,
          }}>
            <div style={{width:34,height:34,borderRadius:9,
              background:`linear-gradient(135deg,${p.accent},${p.cyan})`,
              display:"flex",alignItems:"center",justifyContent:"center",fontSize:21,flexShrink:0}}>📞</div>
            <div style={{flex:1}}>
              <div style={{fontWeight:800,fontSize:18,color:p.text}}>Support Escalation Matrix</div>
              <div style={{fontSize:15,color:p.textMute}}>Wipro CaaS Platform · LaaS Engineering</div>
            </div>
            <button onClick={()=>setOpen(false)} style={{background:"none",border:"none",color:p.textMute,cursor:"pointer",fontSize:20,lineHeight:1,padding:4}}>✕</button>
          </div>

          {/* Escalation flow banner */}
          <div style={{padding:"7px 16px",borderBottom:`1px solid ${p.border}`,
            background:`linear-gradient(90deg,${p.panelAlt},${p.panel})`,
            display:"flex",alignItems:"center",gap:5,flexShrink:0,flexWrap:"wrap"}}>
            <span style={{fontSize:13,fontWeight:700,color:p.textMute,textTransform:"uppercase",letterSpacing:".8px",marginRight:2}}>Escalation Path</span>
            {[
              {label:"Domain Team",  color:"#06b6d4"},
              {label:"Domain Lead",  color:"#8b5cf6"},
              {label:"Eng Head",     color:"#f59e0b"},
              {label:"ADH",          color:"#ef4444"},
            ].map(({label,color},i,arr)=>(
              <span key={label} style={{display:"inline-flex",alignItems:"center",gap:4}}>
                <span style={{
                  fontSize:14,fontWeight:700,padding:"2px 8px",borderRadius:20,
                  background:`${color}18`,color,border:`1px solid ${color}35`,
                }}>{label}</span>
                {i<arr.length-1&&<span style={{color:p.textMute,fontSize:15}}>›</span>}
              </span>
            ))}
          </div>

          {/* Scrollable body */}
          <div style={{overflowY:"auto",flex:1}}>

            {/* ── Leadership ── */}
            <div style={{padding:"10px 14px 6px"}}>
              <div style={{fontSize:13,fontWeight:800,textTransform:"uppercase",letterSpacing:"1.2px",
                color:p.textMute,marginBottom:8,display:"flex",alignItems:"center",gap:6}}>
                <span style={{height:1,flex:1,background:p.border}}/>
                <span>Leadership</span>
                <span style={{height:1,flex:1,background:p.border}}/>
              </div>
              <div style={{display:"flex",flexDirection:"column",gap:4}}>
                {SUPPORT_MATRIX.leadership.map((person,i)=>(
                  <div key={i}>
                    <div style={{
                      display:"flex",alignItems:"center",gap:10,
                      padding:"8px 10px",borderRadius:9,
                      background:`${person.color}10`,border:`1px solid ${person.color}30`,
                    }}>
                      <div style={{width:32,height:32,borderRadius:8,
                        background:`linear-gradient(135deg,${person.color}30,${person.color}15)`,
                        border:`1px solid ${person.color}40`,
                        display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,flexShrink:0}}>
                        {person.icon}
                      </div>
                      <div style={{flex:1,minWidth:0}}>
                        <div style={{fontWeight:700,fontSize:16,color:p.text}}>{person.name}</div>
                        <div style={{fontSize:15,color:person.color,fontWeight:600}}>
                          {person.designation}
                          {person.abbrev&&<span style={{marginLeft:5,opacity:.75,fontSize:14}}>({person.abbrev})</span>}
                        </div>
                      </div>
                      {person.email&&(
                        <div style={{display:"flex",gap:4,flexShrink:0}}>
                          <button title="Copy email" onClick={()=>copyEmail(person.email)} style={{
                            background:copiedEmail===person.email?`${p.green}20`:`${p.border}40`,
                            border:`1px solid ${copiedEmail===person.email?p.green:p.border}`,
                            color:copiedEmail===person.email?p.green:p.textSub,
                            borderRadius:6,padding:"3px 7px",cursor:"pointer",fontSize:14,fontWeight:600,transition:"all .2s",
                          }}>
                            {copiedEmail===person.email?"✓":"📋"}
                          </button>
                          <a href={`mailto:${person.email}`} title={person.email} style={{
                            background:`${p.accent}15`,border:`1px solid ${p.accent}40`,
                            color:p.accent,borderRadius:6,padding:"3px 7px",
                            fontSize:14,fontWeight:600,textDecoration:"none",display:"inline-flex",alignItems:"center",
                          }}>✉️</a>
                        </div>
                      )}
                    </div>
                    {i<SUPPORT_MATRIX.leadership.length-1&&(
                      <div style={{display:"flex",justifyContent:"center",margin:"2px 0"}}>
                        <span style={{color:p.textMute,fontSize:17}}>↓</span>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* ── Domain Teams ── */}
            <div style={{padding:"2px 14px 14px"}}>
              <div style={{fontSize:13,fontWeight:800,textTransform:"uppercase",letterSpacing:"1.2px",
                color:p.textMute,marginBottom:10,marginTop:6,display:"flex",alignItems:"center",gap:6}}>
                <span style={{height:1,flex:1,background:p.border}}/>
                <span>Domain Teams (Report to Engineering Head)</span>
                <span style={{height:1,flex:1,background:p.border}}/>
              </div>
              <div style={{display:"flex",flexDirection:"column",gap:10}}>
                {SUPPORT_MATRIX.domains.map(domain=>(
                  <div key={domain.id} style={{
                    border:`1px solid ${domain.color}30`,borderRadius:10,overflow:"hidden",
                    background:`${domain.color}05`,
                  }}>
                    {/* Domain header */}
                    <div style={{
                      padding:"7px 12px",
                      background:`linear-gradient(90deg,${domain.color}22,${domain.color}08)`,
                      borderBottom:`1px solid ${domain.color}25`,
                      display:"flex",alignItems:"center",gap:8,
                    }}>
                      <span style={{fontSize:19}}>{domain.icon}</span>
                      <span style={{fontWeight:800,fontSize:16,color:domain.color,letterSpacing:".2px"}}>{domain.label}</span>
                    </div>
                    {/* Team hierarchy */}
                    <div style={{padding:"6px 10px 8px",display:"flex",flexDirection:"column",gap:3}}>
                      {domain.team.map((member,mi)=>(
                        <div key={mi} style={{
                          display:"flex",alignItems:"flex-start",gap:6,
                          paddingLeft:mi===0?0:mi===1?10:20,
                        }}>
                          {mi>0&&(
                            <span style={{color:p.textMute,fontSize:16,marginTop:7,lineHeight:1,flexShrink:0}}>↳</span>
                          )}
                          <div style={{
                            flex:1,display:"flex",alignItems:"center",gap:8,
                            padding:"6px 9px",borderRadius:8,
                            background:p.panelAlt,
                            border:`1px solid ${mi===0?domain.color+"28":p.border}`,
                            minWidth:0,
                          }}>
                            <div style={{flex:1,minWidth:0}}>
                              <div style={{display:"flex",alignItems:"center",gap:6,flexWrap:"wrap"}}>
                                <span style={{fontWeight:700,fontSize:15,color:p.text}}>{member.name}</span>
                                <span style={{
                                  fontSize:13,fontWeight:700,padding:"1px 6px",borderRadius:10,
                                  background:`${member.tierColor}20`,color:member.tierColor,
                                  border:`1px solid ${member.tierColor}30`,whiteSpace:"nowrap",flexShrink:0,
                                }}>{member.tier}</span>
                              </div>
                              <div style={{fontSize:14,color:p.textSub,marginTop:1}}>{member.designation}</div>
                              <div style={{fontSize:14,color:domain.color,marginTop:1,fontWeight:500,display:"flex",alignItems:"center",gap:3}}>
                                <span>🔧</span><span>{member.tech}</span>
                              </div>
                            </div>
                            {member.email?(
                              <div style={{display:"flex",gap:3,flexShrink:0}}>
                                <button title="Copy email" onClick={()=>copyEmail(member.email)} style={{
                                  background:copiedEmail===member.email?`${p.green}20`:`${p.border}40`,
                                  border:`1px solid ${copiedEmail===member.email?p.green:p.border}`,
                                  color:copiedEmail===member.email?p.green:p.textSub,
                                  borderRadius:5,padding:"2px 6px",cursor:"pointer",fontSize:14,fontWeight:600,transition:"all .2s",
                                }}>
                                  {copiedEmail===member.email?"✓":"📋"}
                                </button>
                                <a href={`mailto:${member.email}`} title={member.email} style={{
                                  background:`${p.accent}15`,border:`1px solid ${p.accent}40`,
                                  color:p.accent,borderRadius:5,padding:"2px 6px",
                                  fontSize:14,fontWeight:600,textDecoration:"none",display:"inline-flex",alignItems:"center",
                                }}>✉️</a>
                              </div>
                            ):(
                              <span style={{fontSize:13,color:p.textMute,fontStyle:"italic",flexShrink:0}}>Team</span>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Footer */}
          <div style={{
            padding:"7px 14px",borderTop:`1px solid ${p.border}`,flexShrink:0,
            background:p.panelAlt,display:"flex",alignItems:"center",justifyContent:"space-between",
          }}>
            <span style={{fontSize:14,color:p.textMute}}>📋 Copy email · ✉️ Open mail client</span>
            <span style={{fontSize:14,color:p.textMute}}>Wipro LaaS Platform</span>
          </div>
        </div>
      )}
    </div>
  );
}

